        if (frame == null) {
            throw new IllegalStateException("No plugin generation is loaded");
        }
        return frame;
    }

    boolean isBalanced() {
        pruneShadow();
        return shadow.isEmpty();
    }

    void close() {
        TimelineFrame frame = current.getAndSet(null);
        if (frame != null) {
            shadow.add(frame);
